var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"주인어른께서 평소 심려가 많으신 줄은 일찍부터 알고 있었습니다.","JPN":"社長は普段からいろいろ心配事があることは存じております。","ENG":"I knew about the amount of anxiety you had in you, Master.","TWN":"我很早知道，主人是位多慮的人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"저와 같이 흠결이 많은 자가 곁에 있어 봐야, 주인어른의 심려를 더할 따름이겠지요.","JPN":"私のような不甲斐ない者が付き添っても、社長の心配が深まるだけでしょう。","ENG":"And someone like myself, a person with so many flaws, will only add to your anxiety by staying by your side.","TWN":"把我這種滿是缺點的人留在身邊，只會讓主人更加操心吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"이미 많은 짐을 짊어지신 분께 더한 부담이 될 뜻은 한 점 없사오나......","JPN":"すでに重荷を背負っている方に、これ以上負担をかけるつもりは一切ありませんが……","ENG":"I'd rather kill myself than to be a burden on your shoulder, but...","TWN":"主人已經背負很多東西了，我不想再加重主人的負擔，但是……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"사람이란 참 간사한 동물이랍니다.","JPN":"人は実にずる賢い生き物なのです。","ENG":"A human being is a shameless animal.","TWN":"人類真是種狡猾的生物。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그렇게 아니된다고 거듭 다짐했건만...... 말씀을 듣기 무섭게 동요를 일으키다니요.","JPN":"そうしてはいけないと重ね重ね念を押していたのですが……お話を伺ってすぐ動揺してしまうとは。","ENG":"I told myself a million times that it couldn't be, but my heart throbs the moment you call for me.","TWN":"雖然不斷告訴自己不能這麼做……但一聽主人這麼說，我就心生動搖了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"결국 이렇게...... 주위의 비방 중에 옳은 말도 있음을 제 스스로 증명하는군요.","JPN":"結局こうして……他人の批判の中では正しい意見もあることを自ら証明してしまったのですね。","ENG":"In the end, I'm proving that some of the condemnations I've heard about me were true... through my own actions.","TWN":"結果我就這樣……自己證明了周圍對我的誹謗中，也有些沒說錯的話。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"머리로 헤아리지 않고 마음 가는 대로 따르려는 작태가, 어머니와 똑닮았습니다.","JPN":"頭で考えずに思うがままに行動しようとする姿は母親にそっくりです。","ENG":"I'm inclined to follow my heart and not my head. I'm just like how my mother was.","TWN":"不經大腦思考、遵循欲望的醜態，和我母親簡直一模一樣。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"제 어머니도 이윤보다 후회 없는 삶을 걸으라고, 입버릇처럼 말하였습니다.","JPN":"私の母親も利益を追うより悔いのない人生を歩め、と口癖のように言ってました。","ENG":"My mother always said I should pursue life without regrets and not profit.","TWN":"我母親常說比起利益，更要過個沒有遺憾的人生，就像她口頭禪一樣，"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그러더니 정작 자신은 가문을 등졌다가 비참하게 세상을 떠나 버렸지요.","JPN":"しかし、その本人は家門に背いたせいで、惨めな死に方をしたのです。","ENG":"But then she died a miserable death after turning her back on her family.","TWN":"結果她自己卻背叛了家族，最後悲慘地離開了這個世界。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"집안의 죄인이 되어 명을 다했던, 그 마지막 속내가 어떠했는지는 헤아리기 어려우나......","JPN":"家門の罪人となり命を落としたその瞬間の気持ちはどうだったのか、はかりかねますが……","ENG":"She died a sinner. I can't fathom what her last thoughts were...","TWN":"母親成為家族的罪人然後失去性命，她最後一刻的心思為何，我實在無法揣測……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"요즘 들어, 주인어른의 안위를 위해서라면 저 역시 무엇인들 못하겠느냐는 생각이 문득 들고는 합니다.","JPN":"この頃は社長のためなら、私だって何でもできるとふと思ったのです。","ENG":"But nowadays, I keep thinking that for you, I would go even further to keep you from harm.","TWN":"最近我經常在想，如果是為了主人的安危，我什麼都願意做。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"물론 제가 지닌 재주는 무엇 하나 남에게 떳떳이 내보일 것이 아니됩니다.","JPN":"もちろん私の才能は何一つ人に自慢できるものではありません。","ENG":"My skills are wicked, and none of them are worthy of proud display.","TWN":"當然，我擁有技藝，是無法堂堂正正地顯露在他人面前的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"세상에 드러나면 경멸 받기에 마땅한 수작들뿐이죠.","JPN":"世に出したら、軽蔑されるに違いない手品ばかりです。","ENG":"They're petty tricks that would evoke nothing but contempt when the world sees them.","TWN":"我這些小伎倆如果顯露於世，也只會受人輕蔑罷了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"다만...... 주인어른의 뜻을 이루는 데에는 언젠가 작은 쓸모나마 있으리라 믿사옵니다.","JPN":"ですが……社長の志を得るのに多少は役立つと信じております。","ENG":"But... I believe they will be of use at some point in your journey.","TWN":"只是……我相信，在主人實現理想的過程中，我總會有給予主人小小幫助的一天。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그 순간이 올 때까지, 제 모든 것을 다해 보필해 드리겠습니다.","JPN":"その時がくるまで、私のすべてを捧げて補佐いたします。","ENG":"And till that moment comes, I'll be your hands and feet.","TWN":"在那一刻到來之前，我會竭盡全力地輔佐您的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};